import React, { useMemo } from 'react';
import { useLocation } from 'react-router-dom';
import PropTypes from 'prop-types';

import './ArticlesPage.scss';

// eslint-disable-next-line react/prop-types
export const ArticlesPage = ({ article,
  appliedQuery,
  newsTrending,
  // eslint-disable-next-line react/prop-types
  newsCategory,
cli }) => {
  const location = useLocation();
  const searchParams = new URLSearchParams(location.search);
  const category = searchParams.get('category');
  const visibleArticles = useMemo(() => {
    if (category) {
      return newsCategory;
    }

    if (article) {
      return [article];
    }

    return newsTrending;

    // if (article) {
    //   return article;
    // }

    // if (!article) {
    //   return newsTrending;
    // }

  }, [category, newsCategory, newsTrending, article]);
  // const match = useRouteMatch();
  // console.log(match);

  console.log(`Ar-2: ${article}`);
  //console.log(visiblePreview);

  return (
    <div className="ArticlesPage">
      {/* {(article ? [article] : [value]) */}
      {visibleArticles
        .map(item => (
          <div
            key={item}
            className="ArticlesPage-Article Article"
          >
            <div className="Article-Image">
              <img
                className="image-article"
                src={item.image}
                width="1700"
                height="380"
                alt="Foto"
              />
            </div>
            <div className="Article-Content">
              <h1 className="Article-Title">
                {item.title}
              </h1>
              <div className="Article-Info">
                <p className="Article-Author">
                  {`Source "${item.source.name}"`}
                </p>
                <p className="Article-Date">{new Date(item.publishedAt.slice(0, 10)).toString().slice(4, 15)}</p>
              </div>
              {/* <br className="decor" /> */}
              <div className="Article-Summary">
                {/* {value.description} */}
                {item.content.slice(0, -12)}
                {/* Section 1.10.32 of "de Finibus Bonorum et Malorum", written by Cicero in 45 BC "Sed ut perspiciatis unde omnis iste natus error sit voluptatem accusantium doloremque laudantium, totam rem aperiam, eaque ipsa quae ab illo inventore veritatis et quasi architecto beatae vitae dicta sunt explicabo. Nemo enim ipsam voluptatem quia voluptas sit aspernatur aut odit aut fugit, sed quia consequuntur magni dolores eos qui ratione voluptatem sequi nesciunt. Neque porro quisquam est, qui dolorem ipsum quia dolor sit amet, consectetur, adipisci velit, sed quia non numquam eius modi tempora incidunt ut labore et dolore magnam aliquam quaerat voluptatem. Ut enim ad minima veniam, quis nostrum exercitationem ullam corporis suscipit laboriosam, nisi ut aliquid ex ea commodi consequatur? Quis autem vel eum iure reprehenderit qui in ea voluptate velit esse quam nihil molestiae consequatur, vel illum qui dolorem eum fugiat quo voluptas nulla pariatur?" */}
              </div>
            </div>
          </div>
        ))}
    </div>
  );
};

ArticlesPage.propTypes = {
  article: PropTypes.shape({
    title: PropTypes.string,
    content: PropTypes.string,
    image: PropTypes.string,
    source: PropTypes.shape({
      name: PropTypes.string,
    }),
    publishedAt: PropTypes.string,
  }),
  appliedQuery: PropTypes.string.isRequired,
  newsTrending: PropTypes.arrayOf({
    title: PropTypes.string.isRequired,
    description: PropTypes.string.isRequired,
    image: PropTypes.string.isRequired,
  }.isRequired).isRequired,
  // newsCategory: PropTypes.arrayOf({
  //   title: PropTypes.string.isRequired,
  //   description: PropTypes.string.isRequired,
  //   image: PropTypes.string.isRequired,
  // }.isRequired).isRequired,
};

ArticlesPage.defaultProps = {
  // eslint-disable-next-line react/default-props-match-prop-types
  newsCategory: [],
  // eslint-disable-next-line react/default-props-match-prop-types
  article: {},
  // eslint-disable-next-line react/default-props-match-prop-types
  visiblePreview: {},
};
